<div class="de">
<svg viewBox="0 0 700 470" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">Angegebene Zuversicht vs Tatsächliche Trefferquote</text>
  <text x="20" y="48" fill="#71717a" font-size="12" font-family="sans-serif">Drei unabhängige Studien, dasselbe Muster über ein halbes Jahrhundert</text>
  <text x="150" y="72" fill="#a1a1aa" font-size="12.5" font-weight="700">Angegebene Zuversicht</text>
  <text x="150" y="88" fill="#a1a1aa" font-size="12.5" font-weight="700">Tatsächliche Trefferquote</text>
